[CmdletBinding()]param();$ErrorActionPreference='Stop';$root=(Resolve-Path (Join-Path $PSScriptRoot '..')).Path;. (Join-Path $root 'tests/helpers/TypedStudioFixture.ps1');$work=Join-Path ([IO.Path]::GetTempPath()) ('phase4-'+[guid]::NewGuid().ToString('N'));New-Item -ItemType Directory $work|Out-Null
